import{_ as e,H as a,f as i,i as t}from"./chunks/framework.DbTCwA-u.js";const p=JSON.parse('{"title":"Instalação e Requisitos","description":"Aprenda como instalar o EligiusNametag no seu servidor Paper ou Folia.","frontmatter":{"title":"Instalação e Requisitos","description":"Aprenda como instalar o EligiusNametag no seu servidor Paper ou Folia."},"headers":[],"relativePath":"pt/installation.md","filePath":"pt/installation.md"}'),s={name:"pt/installation.md"};function r(n,o,d,l,c,u){return a(),i("div",null,[...o[0]||(o[0]=[t('<h1 id="instalacao-e-requisitos" tabindex="-1">Instalação e Requisitos <a class="header-anchor" href="#instalacao-e-requisitos" aria-label="Permalink to &quot;Instalação e Requisitos&quot;">​</a></h1><p>O EligiusNametag é um plugin moderno e poderoso. Aproveitando os recursos mais recentes da API de texto do Minecraft e o multi-threading, ele requer um ambiente atualizado.</p><h2 id="📋-requisitos-do-sistema" tabindex="-1">📋 Requisitos do Sistema <a class="header-anchor" href="#📋-requisitos-do-sistema" aria-label="Permalink to &quot;📋 Requisitos do Sistema&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Versão Mínima</th><th>Motivo</th></tr></thead><tbody><tr><td><strong>Plataforma</strong></td><td>Paper 1.21 ou Folia 1.21+</td><td>Uso estrito de componentes <code>TEXT_DISPLAY</code> e comandos Brigadier.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Código fonte compilado no formato JDK 21.</td></tr></tbody></table><h2 id="📦-dependencias" tabindex="-1">📦 Dependências <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependências&quot;">​</a></h2><p>Você deve ter os seguintes plugins instalados na sua pasta <code>plugins/</code>:</p><ol><li><strong>ProtocolLib</strong> <em>(Obrigatório)</em>: Usado para enviar os pacotes de hologramas invisivelmente, sem consumir TPS físico.</li><li><strong>Vault</strong> <em>(Opcional)</em>: Se você deseja conceder designs específicos de nametag dependendo do rank do usuário (Admin, VIP, etc.).</li><li><strong>PlaceholderAPI</strong> <em>(Opcional)</em>: Para processar variáveis externas como estatísticas, dinheiro ou clãs nos nametags.</li><li><strong>ItemsAdder</strong> <em>(Opcional)</em>: Para exibir emojis personalizados nos nomes.</li></ol><h2 id="🚀-passos-de-instalacao" tabindex="-1">🚀 Passos de Instalação <a class="header-anchor" href="#🚀-passos-de-instalacao" aria-label="Permalink to &quot;🚀 Passos de Instalação&quot;">​</a></h2><ol><li>Baixe o arquivo <code>EligiusNametag-1.x.x.jar</code> na aba <strong>Releases</strong>.</li><li>Copie o arquivo para o diretório <code>plugins/</code> do seu servidor.</li><li>Certifique-se de ter o <strong>ProtocolLib</strong> instalado.</li><li>Inicie o seu servidor.</li><li>Você verá a animação de inicialização no console com o gato do Eligius MC confirmando que o plugin conectou com sucesso.</li><li>Pronto! Você pode configurar tudo a partir de <code>plugins/EligiusNametag/</code>.</li></ol>',9)])])}const g=e(s,[["render",r]]);export{p as __pageData,g as default};
